import { createORPCClient } from "@orpc/client";
import { RPCLink } from "@orpc/client/fetch";
const createRunableClient = (url) => createORPCClient(new RPCLink({ url }));
const sendEmail = async ({ url, ...email }) => {
  const client = createRunableClient(url);
  return client.email.send(email);
};
export {
  createRunableClient,
  sendEmail
};
